#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N % 2 == 0) {
            // even N: all -1
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) {
                    if (j) printf(" ");
                    printf("-1");
                }
                printf("\n");
            }
        } else {
            // odd N: 1 everywhere, -1 on diagonal
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) {
                    if (j) printf(" ");
                    if (i == j) printf("-1");
                    else printf("1");
                }
                printf("\n");
            }
        }
    }
    return 0;
}

