import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            if (N % 2 == 0) {
                // even N: all -1
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < N; j++) {
                        if (j > 0) out.append(' ');
                        out.append(-1);
                    }
                    out.append('\n');
                }
            } else {
                // odd N: 1 everywhere, -1 on diagonal
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < N; j++) {
                        if (j > 0) out.append(' ');
                        out.append(i == j ? -1 : 1);
                    }
                    out.append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
}

