import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        if N % 2 == 0:
            # even N: all -1
            row = ' '.join(['-1'] * N)
            for _ in range(N):
                out_lines.append(row)
        else:
            # odd N: 1 everywhere, -1 on diagonal
            for i in range(N):
                line = []
                for j in range(N):
                    line.append('-1' if i == j else '1')
                out_lines.append(' '.join(line))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

